features.snippet:
logic clk, rst_n;
logic [7:0] q;
always_ff @(posedge clk or negedge rst_n) begin
  if (!rst_n)
    q <= 8'h00;
  else
    q <= q + 1;
end

logic clk, rst;
logic [7:0] q;
always_ff @(posedge clk) begin
  if (rst)
    q <= 8'h00;
  else
    q <= q + 1;
end

logic clk, rst_n, en;
logic [7:0] d, q;
always_ff @(posedge clk or negedge rst_n) begin
  if (!rst_n)
    q <= 8'h00;
  else if (en)
    q <= d;
end
